outputs = {"sum":"float"}
def process(list):
    """Sum all numeric values in a list"""
    if not list or not isinstance(list, (list, tuple)):
        return 0.0
    total = 0.0
    for item in list:
        try:
            total += float(item)
        except (TypeError, ValueError):
            pass
    return total
